using System.IdentityModel.Tokens.Jwt; using System.Security.Claims; using System.Text; using Financeiro.Application.DTOs; using Financeiro.Application.Interfaces; using Financeiro.Infrastructure.Configurations; using Microsoft.Extensions.Options; using Microsoft.IdentityModel.Tokens;
namespace Financeiro.Infrastructure.Authentication; public class JwtTokenGenerator : IJwtTokenGenerator { private readonly JwtSettings _settings; public JwtTokenGenerator(IOptions<JwtSettings> options){_settings=options.Value;} public AuthResponseDto Generate(Guid userId,string name,string email,string role){ var key=new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_settings.Key)); var creds=new SigningCredentials(key,SecurityAlgorithms.HmacSha256); var exp=DateTime.UtcNow.AddMinutes(_settings.ExpirationInMinutes); var claims=new[]{ new Claim(JwtRegisteredClaimNames.Sub,userId.ToString()), new Claim(JwtRegisteredClaimNames.Name,name), new Claim(JwtRegisteredClaimNames.Email,email), new Claim(ClaimTypes.Role,role), new Claim(JwtRegisteredClaimNames.Jti,Guid.NewGuid().ToString())}; var token=new JwtSecurityToken(_settings.Issuer,_settings.Audience,claims,expires:exp,signingCredentials:creds); return new AuthResponseDto{Token=new JwtSecurityTokenHandler().WriteToken(token),ExpiresAt=exp,Name=name,Email=email,Role=role}; } }
